   155→/// Rail - reorder Paces within a Heat
   156→///
   157→/// Supports two modes:
   158→/// - Order mode: replace entire sequence with provided order array
   159→/// - Move mode: relocate a single pace using positioning flags
   160→pub fn jjrg_rail(gallops: &mut jjrg_Gallops, args: jjrg_RailArgs) -> Result<Vec<String>, String> {
   161→    // Parse and normalize firemark
   162→    let firemark = Firemark::jjrf_parse(&args.firemark)
   163→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   164→    let firemark_key = firemark.jjrf_display();
   165→
   166→    // Verify Heat exists
   167→    let heat = gallops.heats.get_mut(&firemark_key)
   168→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   169→
   170→    // Mode detection: if move_coronet present, use move mode
   171→    if let Some(ref move_str) = args.move_coronet {
   172→        // Move mode validation
   173→        if !args.order.is_empty() {
   174→            return Err("Cannot combine --move with positional coronets".to_string());
   175→        }
   176→
   177→        // Parse and normalize move coronet
   178→        let move_coronet = Coronet::jjrf_parse(move_str)
   179→            .map_err(|e| format!("Invalid --move coronet: {}", e))?;
   180→        let move_key = move_coronet.jjrf_display();
   181→
   182→        // Validate move coronet exists in heat
   183→        if !heat.paces.contains_key(&move_key) {
   184→            return Err(format!("Pace {} not found in heat {}", move_key, firemark_key));
   185→        }
   186→
   187→        // Count positioning flags
   188→        let position_count = [
   189→            args.before.is_some(),
   190→            args.after.is_some(),
   191→            args.first,
   192→            args.last,
   193→        ].iter().filter(|&&x| x).count();
   194→
   195→        if position_count == 0 {
   196→            return Err("Move mode requires exactly one positioning flag".to_string());
   197→        }
   198→        if position_count > 1 {
   199→            let mut flags = Vec::new();
   200→            if args.before.is_some() { flags.push("--before"); }
   201→            if args.after.is_some() { flags.push("--after"); }
   202→            if args.first { flags.push("--first"); }
   203→            if args.last { flags.push("--last"); }
   204→            return Err(format!("Conflicting positioning flags: {}", flags.join(", ")));
   205→        }
   206→
   207→        // Determine target position and validate
   208→        let current_pos = heat.order.iter().position(|c| c == &move_key)
   209→            .ok_or_else(|| format!("Pace {} not in order array", move_key))?;
   210→
   211→        let new_pos = if args.first {
   212→            // Find first actionable pace (rough or bridled)
   213→            // If none found, use end of array (nothing actionable to precede)
   214→            let first_actionable_idx = heat.order.iter().position(|coronet| {
   215→                if let Some(pace) = heat.paces.get(coronet) {
   216→                    if let Some(tack) = pace.tacks.first() {
   217→                        matches!(tack.state, jjrg_PaceState::Rough | jjrg_PaceState::Bridled)
   218→                    } else {
   219→                        false
   220→                    }
   221→                } else {
   222→                    false
   223→                }
   224→            });
   225→            // Use len() as fallback so adjustment logic works correctly for "end" position
   226→            let target_idx = first_actionable_idx.unwrap_or(heat.order.len());
   227→            // If moving from before target, the target shifts down after removal
   228→            if current_pos < target_idx {
   229→                target_idx - 1
   230→            } else {
   231→                target_idx
   232→            }
   233→        } else if args.last {
   234→            heat.order.len() - 1
   235→        } else if let Some(ref before_str) = args.before {
   236→            let target = Coronet::jjrf_parse(before_str)
   237→                .map_err(|e| format!("Invalid --before coronet: {}", e))?;
   238→            let target_key = target.jjrf_display();
   239→
   240→            if target_key == move_key {
   241→                return Err("Cannot position pace relative to itself".to_string());
   242→            }
   243→
   244→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   245→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   246→
   247→            // If moving from before target, the target shifts down after removal
   248→            if current_pos < target_pos {
   249→                target_pos - 1
   250→            } else {
   251→                target_pos
   252→            }
   253→        } else if let Some(ref after_str) = args.after {
   254→            let target = Coronet::jjrf_parse(after_str)
   255→                .map_err(|e| format!("Invalid --after coronet: {}", e))?;
   256→            let target_key = target.jjrf_display();
   257→
   258→            if target_key == move_key {
   259→                return Err("Cannot position pace relative to itself".to_string());
   260→            }
   261→
   262→            let target_pos = heat.order.iter().position(|c| c == &target_key)
   263→                .ok_or_else(|| format!("Target pace {} not found in heat {}", target_key, firemark_key))?;
   264→
   265→            // If moving from before target, the target shifts down after removal
   266→            if current_pos < target_pos {
   267→                target_pos // After removal, target is at target_pos-1, we want target_pos-1+1 = target_pos
   268→            } else {
   269→                target_pos + 1
   270→            }
   271→        } else {
   272→            unreachable!()
   273→        };
   274→
   275→        // Remove from current position and insert at new position
   276→        heat.order.remove(current_pos);
   277→        heat.order.insert(new_pos, move_key);
   278→
   279→    } else {
   280→        // Order mode: replace entire sequence
   281→
   282→        // Normalize the input order (add prefix if missing)
   283→        let normalized_order: Result<Vec<String>, String> = args.order.iter()
   284→            .map(|c| {
   285→                let coronet = Coronet::jjrf_parse(c)
   286→                    .map_err(|e| format!("Invalid coronet '{}': {}", c, e))?;
   287→                Ok(coronet.jjrf_display())
   288→            })
   289→            .collect();
   290→        let new_order = normalized_order?;
   291→
   292→        // Validate count matches
   293→        if new_order.len() != heat.order.len() {
   294→            return Err(format!(
   295→                "Order count mismatch: got {}, expected {}",
   296→                new_order.len(),
   297→                heat.order.len()
   298→            ));
   299→        }
   300→
   301→        // Validate no duplicates
   302→        let new_set: HashSet<&String> = new_order.iter().collect();
   303→        if new_set.len() != new_order.len() {
   304→            return Err("Order contains duplicate Coronets".to_string());
   305→        }
   306→
   307→        // Validate all Coronets exist in paces
   308→        for coronet in &new_order {
   309→            if !heat.paces.contains_key(coronet) {
   310→                return Err(format!("Coronet '{}' not found in Heat's paces", coronet));
   311→            }
   312→        }
   313→
   314→        // Validate all Coronets embed correct parent Firemark
   315→        for coronet in &new_order {
   316→            let c = Coronet::jjrf_parse(coronet).unwrap();
   317→            if c.jjrf_parent_firemark().jjrf_display() != firemark_key {
   318→                return Err(format!(
   319→                    "Coronet '{}' does not embed parent Heat '{}'",
   320→                    coronet, firemark_key
   321→                ));
   322→            }
   323→        }
   324→
   325→        // Replace order
   326→        heat.order = new_order;
   327→    }
   328→
   329→    // Return the new order
   330→    Ok(heat.order.clone())
   331→}
