   636→/// Build trophy markdown content
   637→fn zjjrg_build_trophy_content(
   638→    firemark_key: &str,
   639→    heat: &jjrg_Heat,
   640→    paddock_content: &str,
   641→    today: &str,
   642→    steeplechase: &[SteeplechaseEntry],
   643→) -> Result<String, String> {
   644→    let mut content = String::new();
   645→
   646→    // Header
   647→    content.push_str(&format!("# Heat Trophy: {}\n\n", heat.silks));
   648→    content.push_str(&format!("**Firemark:** {}\n", firemark_key));
   649→    content.push_str(&format!("**Created:** {}\n", heat.creation_time));
   650→    content.push_str(&format!("**Retired:** {}\n", today));
   651→    content.push_str("**Status:** retired\n\n");
   652→
   653→    // Paddock
   654→    content.push_str("## Paddock\n\n");
   655→    content.push_str(paddock_content);
   656→    if !paddock_content.ends_with('\n') {
   657→        content.push('\n');
   658→    }
   659→    content.push('\n');
   660→
   661→    // Paces (in order)
   662→    content.push_str("## Paces\n\n");
   663→    for coronet_key in &heat.order {
   664→        if let Some(pace) = heat.paces.get(coronet_key) {
   665→            // Get final state from most recent tack
   666→            let final_state = pace.tacks.first()
   667→                .map(|t| match t.state {
   668→                    jjrg_PaceState::Rough => "rough",
   669→                    jjrg_PaceState::Bridled => "bridled",
   670→                    jjrg_PaceState::Complete => "complete",
   671→                    jjrg_PaceState::Abandoned => "abandoned",
   672→                })
   673→                .unwrap_or("unknown");
   674→
   675→            let pace_silks = pace.tacks.first()
   676→                .map(|t| t.silks.as_str())
   677→                .unwrap_or("unknown");
   678→
   679→            content.push_str(&format!(
   680→                "### {} ({}) [{}]\n\n",
   681→                pace_silks, coronet_key, final_state
   682→            ));
   683→
   684→            // Tack history (newest first, as stored)
   685→            for tack in &pace.tacks {
   686→                let state_str = match tack.state {
   687→                    jjrg_PaceState::Rough => "rough",
   688→                    jjrg_PaceState::Bridled => "bridled",
   689→                    jjrg_PaceState::Complete => "complete",
   690→                    jjrg_PaceState::Abandoned => "abandoned",
   691→                };
   692→                content.push_str(&format!("**[{}] {}**\n\n", tack.ts, state_str));
   693→                content.push_str(&tack.text);
   694→                if !tack.text.ends_with('\n') {
   695→                    content.push('\n');
   696→                }
   697→                if let Some(ref direction) = tack.direction {
   698→                    content.push_str(&format!("\n*Direction:* {}\n", direction));
   699→                }
   700→                content.push('\n');
   701→            }
   702→        }
   703→    }
   704→
   705→    // Steeplechase (newest first, as provided)
   706→    content.push_str("## Steeplechase\n\n");
   707→    if steeplechase.is_empty() {
   708→        content.push_str("(no entries)\n\n");
   709→    } else {
   710→        for entry in steeplechase {
   711→            // Format: ### {date} - {coronet or "Heat"} - {action or "notch"}
   712→            let identity = entry.coronet.as_deref().unwrap_or("Heat");
   713→            let action = entry.action.as_deref().unwrap_or("notch");
   714→            content.push_str(&format!(
   715→                "### {} - {} - {}\n\n",
   716→                entry.timestamp, identity, action
   717→            ));
   718→            content.push_str(&entry.subject);
   719→            if !entry.subject.ends_with('\n') {
   720→                content.push('\n');
   721→            }
   722→            content.push('\n');
   723→        }
   724→    }
   725→
   726→    Ok(content)
   727→}
