   729→/// Furlough a Heat - change status or rename
   730→///
   731→/// Updates heat status (racing/stabled) and/or silks.
   732→/// At least one change must be requested.
   733→pub fn jjrg_furlough(gallops: &mut jjrg_Gallops, args: jjrg_FurloughArgs) -> Result<(), String> {
   734→    // Validate at least one option provided
   735→    if !args.racing && !args.stabled && args.silks.is_none() {
   736→        return Err("At least one option required: --racing, --stabled, or --silks".to_string());
   737→    }
   738→
   739→    // Validate racing/stabled mutual exclusivity
   740→    if args.racing && args.stabled {
   741→        return Err("Cannot specify both --racing and --stabled".to_string());
   742→    }
   743→
   744→    // Validate silks if provided
   745→    if let Some(ref silks) = args.silks {
   746→        if !zjjrg_is_kebab_case(silks) {
   747→            return Err(format!("silks must be kebab-case, got '{}'", silks));
   748→        }
   749→    }
   750→
   751→    // Parse and normalize firemark
   752→    let firemark = Firemark::jjrf_parse(&args.firemark)
   753→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   754→    let firemark_key = firemark.jjrf_display();
   755→
   756→    // Verify Heat exists
   757→    let heat = gallops.heats.get_mut(&firemark_key)
   758→        .ok_or_else(|| format!("Heat '{}' not found", firemark_key))?;
   759→
   760→    // Check not retired (terminal state)
   761→    if heat.status == jjrg_HeatStatus::Retired {
   762→        return Err(format!("Heat '{}' is retired (terminal state)", firemark_key));
   763→    }
   764→
   765→    // Apply status change if requested
   766→    if args.racing {
   767→        if heat.status == jjrg_HeatStatus::Racing {
   768→            return Err(format!("Heat '{}' is already racing", firemark_key));
   769→        }
   770→        heat.status = jjrg_HeatStatus::Racing;
   771→    } else if args.stabled {
   772→        if heat.status == jjrg_HeatStatus::Stabled {
   773→            return Err(format!("Heat '{}' is already stabled", firemark_key));
   774→        }
   775→        heat.status = jjrg_HeatStatus::Stabled;
   776→    }
   777→
   778→    // Apply silks change if requested
   779→    if let Some(silks) = args.silks {
   780→        heat.silks = silks;
   781→    }
   782→
   783→    Ok(())
   784→}
